import{_ as a,o,c as t,a0 as d}from"./chunks/framework.CSGB4SNl.js";const f=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"vue/vue-day02.md","filePath":"vue/vue-day02.md"}'),i={name:"vue/vue-day02.md"};function r(l,e,n,u,c,v){return o(),t("div",null,[...e[0]||(e[0]=[d('<h4 id="说说你对vue生命周期的理解" tabindex="-1">说说你对vue生命周期的理解 <a class="header-anchor" href="#说说你对vue生命周期的理解" aria-label="Permalink to &quot;说说你对vue生命周期的理解&quot;">​</a></h4><ol><li>vue的生命周期包含8个阶段：创建前后、载入前后、更新前后、销毁前后、还有特殊的</li><li>创建前后(组件实例被创建之初、被完全创建)：beforeCreate、created，挂载前后(组件挂载之前、组件被挂载到实例之后)：beforeMount、mounted，更新前后(组件数据发生变化更新之前，组件数据更新之后)：beforeUpdate、updated，销毁前后(组件销毁前销毁后)：beforeDestroy、destroyed，activated(keep-alive缓存组件激活时)，deactivated(keep-alive 缓存的组件停用时调用)，errorCaptured(捕获一个来自子孙组件的错误时被调用)</li><li>流程：beforeCreate-初始化vue示例进行数据观测-》created-完成数据观测属性方法的计算、watch/event回调配置，computed/watch/methods都可以用，也可以修改data里面的来响应式改变dom，但是vm.$el没被创建-》beforeMount-判断是否存在el选项，否则等到vm.$mount(el)才会继续编译，vm.el是获取到挂载dom的-》mounted-完成vm.el的挂载与渲染-》beforeUpdate-更新的数据必须得是渲染在模板上的若再次修改数据则不会更新-》updated-完成view层的更新会触发更新方法-》beforeDestroy-销毁组件前调用里面的属性和方法仍可以访问-》destroyed-销毁组件解除与其它示例/组件的连接、销毁里面的事件监听器、指令、方法属性等，但是并没有清除dom只是销毁示例</li><li>created一般是dom还未完成渲染就调用的，mounted是dom渲染完成后调用，如果有对页面的改动建议放在created因为页面dom已经渲染再去改可能会导致页面闪动</li></ol><h4 id="v-if和v-for的优先级是什么" tabindex="-1">v-if和v-for的优先级是什么？ <a class="header-anchor" href="#v-if和v-for的优先级是什么" aria-label="Permalink to &quot;v-if和v-for的优先级是什么？&quot;">​</a></h4><ol><li>作用在同一元素上时，for的优先级比if高，所以这两者尽量不要一起用，因为会造成先列表渲染在判断是否展示浪费了性能</li><li>不同元素上时才会先判断再列表渲染</li></ol><h4 id="spa首屏加载速度慢的怎么解决" tabindex="-1">SPA首屏加载速度慢的怎么解决？ <a class="header-anchor" href="#spa首屏加载速度慢的怎么解决" aria-label="Permalink to &quot;SPA首屏加载速度慢的怎么解决？&quot;">​</a></h4><ol><li>首屏加载时间指的是，浏览器从响应用户输入网址到首屏内容渲染完成所需要的时间,此时整个网页不一定要全部完成渲染，但需要展示当前视窗需要的资源</li><li>performance、DOMContentLoaded进行计算，加载慢的原因：网络延时问题、资源文件体积是否过大、资源是否重复发送请求去加载了、加载脚本的时候，渲染内容堵塞了</li><li>SPA方面优化：减小入口文件积（动态加载路由）、静态资源本地缓存（localStorage）、UI框架按需加载、图片资源的压缩、组件重复打包（webpack的config修改<code>CommonsChunkPlugin</code>的配置-minChunks表示会把使用对应次数的包抽离成公共资源）、开启GZip压缩（icon、精灵图拼接）、使用SSR（服务端组装html页面）</li></ol><h4 id="为什么data属性是一个函数而不是一个对象" tabindex="-1">为什么data属性是一个函数而不是一个对象？ <a class="header-anchor" href="#为什么data属性是一个函数而不是一个对象" aria-label="Permalink to &quot;为什么data属性是一个函数而不是一个对象？&quot;">​</a></h4><ol><li>如果是在vue实例上data既可以是函数也可以是对象，组件上就只能是函数如果用对象则会报警告信息</li><li>为啥组件中得是函数，因为如果我new了两个Com组件，两个示例都会共享data对象中的数据因为指向同一个内存地址，换成函数则会返回不同内存地址的对象</li><li>那为啥new一个vue实例时可以，因为在源码中对vue实例的data类型定义就是既可以函数也可以对象且根组件是单例的不会出现数据互相影响，组件的话会校验vm对象是否为undifend，是则进入if判断如果不为function就爆警告</li></ol>',8)])])}const s=a(i,[["render",r]]);export{f as __pageData,s as default};
